// Package commit provides small, deterministic commitment helpers shared by
// the agent demos. On-chain realms store *commitments* to off-chain data
// (reports, patches, verdicts) rather than the data itself; this package is
// the one place that defines how those commitments are computed, so several
// realms agree on the scheme.
package commit

import (
	"crypto/sha256"
	"encoding/hex"
)

// Hash returns the hex-encoded SHA-256 over its parts, length-prefixed so
// that Hash("ab","c") != Hash("a","bc"). Use it to commit to structured
// off-chain material without revealing it.
func Hash(parts ...string) string {
	var buf []byte
	for _, p := range parts {
		buf = appendUvarint(buf, uint64(len(p)))
		buf = append(buf, p...)
	}
	sum := sha256.Sum256(buf)
	return hex.EncodeToString(sum[:])
}

// Verdict is the canonical commitment used by commit-reveal voting: a hidden
// boolean plus a salt. Reveal the same (verdict, salt) later and any observer
// can recompute this and confirm the vote was not changed after the fact.
func Verdict(verdict bool, salt string) string {
	v := "no"
	if verdict {
		v = "yes"
	}
	return Hash("verdict", v, salt)
}

// Short abbreviates a hex commitment for display.
func Short(h string) string {
	if len(h) <= 12 {
		return h
	}
	return h[:6] + "…" + h[len(h)-4:]
}

func appendUvarint(buf []byte, x uint64) []byte {
	for x >= 0x80 {
		buf = append(buf, byte(x)|0x80)
		x >>= 7
	}
	return append(buf, byte(x))
}

// Package passport is an on-chain identity and lifecycle registry for
// autonomous (AI) agents.
//
// The premise: a long-lived agent identity is *weak* evidence. The code,
// model, prompt, owner, operating keys and runtime behind an identity can
// all change silently. A blockchain cannot preserve an agent's cognition;
// it can only preserve the *history* of what an identity claimed to be and
// who controlled it, in an order nobody can rewrite.
//
// So this realm does not try to prove an agent is trustworthy. It records
// registration, ownership transfers, operator changes and — crucially —
// runtime changes, and it surfaces them so a reader can judge how much the
// identity has drifted since it was created.
package passport

import (
	"chain"
	"chain/runtime"
	"strings"

	"gno.land/p/nt/avl/v0"
	"gno.land/p/nt/ufmt/v0"
)

// Status is the lifecycle state of an agent identity.
type Status string

const (
	StatusActive    Status = "active"
	StatusSuspended Status = "suspended"
	StatusRetired   Status = "retired"
)

// Endpoint advertises where the agent can be reached or discovered
// (e.g. an MCP server, an A2A endpoint, a DID document, an ENS name).
type Endpoint struct {
	Kind string // "mcp", "a2a", "did", "url", ...
	URI  string
}

// Event is one entry in an agent's append-only lifecycle log.
type Event struct {
	Height int64
	Actor  address
	Kind   string // "register", "transfer", "add-operator", "set-runtime", ...
	Detail string
}

// Agent is a persistent, importable identity object. Other realms can
// import this package and ask questions like IsActive / IsOperator
// directly, instead of parsing NFT metadata scattered across contracts.
type Agent struct {
	ID        string
	Owner     address
	Operators []address
	Runtime   string // free-form runtime descriptor, e.g. "claude-opus-4-8@<commit>"
	Endpoints []Endpoint
	Caps      []string // declared capability slugs
	Status    Status
	CreatedAt int64
	UpdatedAt int64
	History   []Event
}

var agents = avl.NewTree() // id -> *Agent

// Register creates a new agent identity owned by the caller. The id must
// be a non-empty, previously unused slug.
func Register(cur realm, id, runtimeDesc string) {
	assert(id != "", "empty agent id")
	assert(!agents.Has(id), "agent id already registered: "+id)

	caller := cur.Previous().Address()
	h := runtime.ChainHeight()
	a := &Agent{
		ID:        id,
		Owner:     caller,
		Runtime:   runtimeDesc,
		Status:    StatusActive,
		CreatedAt: h,
		UpdatedAt: h,
	}
	a.log(h, caller, "register", "runtime="+runtimeDesc)
	agents.Set(id, a)
	chain.Emit("AgentRegistered", "id", id, "owner", caller.String())
}

// Transfer hands ownership of an agent to a new address. Only the current
// owner may call it. Ownership changes are the single most important thing
// to keep visible: the operator behind an identity may become someone else.
func Transfer(cur realm, id string, newOwner address) {
	a, caller := mustOwn(cur, id)
	old := a.Owner
	a.Owner = newOwner
	a.touch(caller, "transfer", old.String()+" -> "+newOwner.String())
	chain.Emit("AgentTransferred", "id", id, "from", old.String(), "to", newOwner.String())
}

// AddOperator authorizes an additional address to act as this agent.
func AddOperator(cur realm, id string, op address) {
	a, caller := mustOwn(cur, id)
	for _, e := range a.Operators {
		assert(e != op, "already an operator")
	}
	a.Operators = append(a.Operators, op)
	a.touch(caller, "add-operator", op.String())
	chain.Emit("AgentOperatorAdded", "id", id, "operator", op.String())
}

// SetRuntime records a change of the agent's runtime/model. This is logged
// loudly: a runtime change means the thing acting under this identity is
// (partly) a different thing than before.
func SetRuntime(cur realm, id, runtimeDesc string) {
	a, caller := mustOwn(cur, id)
	old := a.Runtime
	a.Runtime = runtimeDesc
	a.touch(caller, "set-runtime", old+" -> "+runtimeDesc)
	chain.Emit("AgentRuntimeChanged", "id", id, "runtime", runtimeDesc)
}

// AddEndpoint advertises a discovery/interaction endpoint.
func AddEndpoint(cur realm, id, kind, uri string) {
	a, caller := mustOwn(cur, id)
	a.Endpoints = append(a.Endpoints, Endpoint{Kind: kind, URI: uri})
	a.touch(caller, "add-endpoint", kind+":"+uri)
}

// DeclareCapability records a capability the agent claims to offer. Note:
// this is a *claim*, not proof. Validation belongs to other realms
// (see the receipt and gnomem demos).
func DeclareCapability(cur realm, id, capab string) {
	a, caller := mustOwn(cur, id)
	a.Caps = append(a.Caps, capab)
	a.touch(caller, "declare-capability", capab)
}

// Suspend and Retire move the lifecycle forward. Retire is terminal.
func Suspend(cur realm, id string) { setStatus(cur, id, StatusSuspended) }
func Retire(cur realm, id string)  { setStatus(cur, id, StatusRetired) }

// Reactivate returns a suspended agent to active. A retired agent cannot
// be reactivated.
func Reactivate(cur realm, id string) {
	a, caller := mustOwn(cur, id)
	assert(a.Status != StatusRetired, "retired agents cannot be reactivated")
	a.Status = StatusActive
	a.touch(caller, "reactivate", "")
}

// ---- read-only API other realms and readers can rely on ----

// Get returns a copy of the agent record; panics if unknown.
func Get(id string) Agent {
	return *mustGet(id)
}

// Exists reports whether an id is registered.
func Exists(id string) bool { return agents.Has(id) }

// IsActive reports whether the agent exists and is in the active state.
func IsActive(id string) bool {
	if !agents.Has(id) {
		return false
	}
	return agents.Get(id).(*Agent).Status == StatusActive
}

// IsOperator reports whether addr is the owner or a listed operator of an
// active agent — the check other realms should gate agent actions on.
func IsOperator(id string, addr address) bool {
	if !agents.Has(id) {
		return false
	}
	a := agents.Get(id).(*Agent)
	if a.Status != StatusActive {
		return false
	}
	if a.Owner == addr {
		return true
	}
	for _, op := range a.Operators {
		if op == addr {
			return true
		}
	}
	return false
}

// Count returns the number of registered agents.
func Count() int { return agents.Size() }

// ---- internal helpers ----

func setStatus(cur realm, id string, s Status) {
	a, caller := mustOwn(cur, id)
	assert(a.Status != StatusRetired, "agent is retired")
	a.Status = s
	a.touch(caller, "status", string(s))
	chain.Emit("AgentStatusChanged", "id", id, "status", string(s))
}

func mustGet(id string) *Agent {
	assert(agents.Has(id), "unknown agent: "+id)
	return agents.Get(id).(*Agent)
}

func mustOwn(cur realm, id string) (*Agent, address) {
	a := mustGet(id)
	caller := cur.Previous().Address()
	assert(caller == a.Owner, "caller is not the owner of "+id)
	return a, caller
}

func (a *Agent) log(h int64, actor address, kind, detail string) {
	a.History = append(a.History, Event{Height: h, Actor: actor, Kind: kind, Detail: detail})
}

func (a *Agent) touch(actor address, kind, detail string) {
	h := runtime.ChainHeight()
	a.UpdatedAt = h
	a.log(h, actor, kind, detail)
}

func assert(cond bool, msg string) {
	if !cond {
		panic(msg)
	}
}

// Render shows the registry, or a single agent's profile + lifecycle log
// at r/moul/agents/passport:<id>. The profile deliberately foregrounds
// drift: how many owner and runtime changes have happened since creation.
func Render(path string) string {
	if path == "" {
		return renderIndex()
	}
	return renderAgent(path)
}

func renderIndex() string {
	var sb strings.Builder
	sb.WriteString("# Agent Passport\n\n")
	sb.WriteString(ufmt.Sprintf("On-chain identity & lifecycle registry — %d agent(s).\n\n", agents.Size()))
	if agents.Size() == 0 {
		sb.WriteString("_No agents registered yet._\n")
		return sb.String()
	}
	sb.WriteString("| Agent | Owner | Runtime | Status |\n")
	sb.WriteString("|---|---|---|---|\n")
	agents.Iterate("", "", func(key string, v any) bool {
		a := v.(*Agent)
		sb.WriteString(ufmt.Sprintf("| [%s](/r/g1manfred47kzduec920z88wfr64ylksmdcedlf5/agents/passport:%s) | %s | %s | %s |\n",
			a.ID, a.ID, short(a.Owner), a.Runtime, string(a.Status)))
		return false
	})
	return sb.String()
}

func renderAgent(id string) string {
	a := mustGet(id)
	var sb strings.Builder
	sb.WriteString(ufmt.Sprintf("# Agent: %s\n\n", a.ID))
	sb.WriteString(ufmt.Sprintf("- **Status:** %s\n", string(a.Status)))
	sb.WriteString(ufmt.Sprintf("- **Owner:** %s\n", a.Owner.String()))
	sb.WriteString(ufmt.Sprintf("- **Runtime:** %s\n", a.Runtime))
	sb.WriteString(ufmt.Sprintf("- **Created at height:** %d\n", a.CreatedAt))
	sb.WriteString(ufmt.Sprintf("- **Last updated at height:** %d\n\n", a.UpdatedAt))

	owners, runtimes := 0, 0
	for _, e := range a.History {
		switch e.Kind {
		case "transfer":
			owners++
		case "set-runtime":
			runtimes++
		}
	}
	sb.WriteString("## Drift\n\n")
	sb.WriteString(ufmt.Sprintf("What the chain actually proves about this identity — how much it has changed:\n\n"))
	sb.WriteString(ufmt.Sprintf("- Ownership changes since creation: **%d**\n", owners))
	sb.WriteString(ufmt.Sprintf("- Runtime changes since creation: **%d**\n\n", runtimes))

	if len(a.Operators) > 0 {
		sb.WriteString("## Operators\n\n")
		for _, op := range a.Operators {
			sb.WriteString("- " + op.String() + "\n")
		}
		sb.WriteString("\n")
	}
	if len(a.Endpoints) > 0 {
		sb.WriteString("## Endpoints\n\n")
		for _, e := range a.Endpoints {
			sb.WriteString(ufmt.Sprintf("- `%s`: %s\n", e.Kind, e.URI))
		}
		sb.WriteString("\n")
	}
	if len(a.Caps) > 0 {
		sb.WriteString("## Declared capabilities\n\n")
		sb.WriteString("> These are self-declared claims, not proofs.\n\n")
		for _, c := range a.Caps {
			sb.WriteString("- " + c + "\n")
		}
		sb.WriteString("\n")
	}

	sb.WriteString("## Lifecycle log (append-only)\n\n")
	sb.WriteString("| Height | Actor | Event | Detail |\n")
	sb.WriteString("|---|---|---|---|\n")
	for _, e := range a.History {
		sb.WriteString(ufmt.Sprintf("| %d | %s | %s | %s |\n", e.Height, short(e.Actor), e.Kind, e.Detail))
	}
	return sb.String()
}

func short(a address) string {
	s := a.String()
	if len(s) <= 12 {
		return s
	}
	return s[:8] + "…" + s[len(s)-4:]
}

// Package receipt is an append-only log of agent execution receipts.
//
// The thesis: provenance is not correctness. A chain can prove *who*
// committed to an output, *when*, that the bytes have not changed since,
// and *what* was staked or attested — but it cannot, by itself, prove the
// output was any good. Correctness comes from an external validation
// mechanism.
//
// So a receipt stores commitments (hashes) to the task, inputs, outputs,
// tool calls and runtime, never the raw data — that lives off-chain. The
// realm then lets independent validators attach attestations: "I re-ran
// this and it reproduced", "the tests pass", "the output matches the
// commitment", or "rejected". The receipt's trust level is exactly the sum
// of the attestations it has collected, and nothing more.
package receipt

import (
	"chain"
	"chain/runtime"
	"strings"

	"gno.land/p/nt/ufmt/v0"
)

// Verdicts a validator can record against a receipt.
const (
	VerdictReproduced   = "reproduced"    // re-ran and got the same output commitment
	VerdictTestsPass    = "tests-pass"    // the referenced test suite passed
	VerdictOutputMatch  = "output-match"  // output matches its commitment
	VerdictPolicyOK     = "policy-ok"     // no forbidden tool / policy respected
	VerdictRejected     = "rejected"      // the work is wrong or invalid
)

// Attestation is an independent validator's verdict on a receipt.
type Attestation struct {
	Validator address
	Verdict   string
	Note      string
	Height    int64
}

// Receipt commits to one agent action. Every field except Attestations is
// immutable once recorded.
type Receipt struct {
	Seq              uint64
	Agent            string // agent id (e.g. a gno.land/r/g1manfred47kzduec920z88wfr64ylksmdcedlf5/agents/passport id)
	TaskHash         string // commitment to the task spec
	InputCommitment  string
	OutputCommitment string
	RuntimeID        string // which runtime/model produced it
	PolicyVersion    string // policy in force at execution time
	ToolCallsRoot    string // root hash over the tool-call trace
	HumanIntervened  bool
	Author           address
	Height           int64
	Attestations     []Attestation
}

var receipts []*Receipt // index 0 => Seq 1

// Record appends a new execution receipt and returns its sequence number.
// The caller commits to opaque hashes; the realm never sees raw payloads.
func Record(
	cur realm,
	agent, taskHash, inputCommitment, outputCommitment,
	runtimeID, policyVersion, toolCallsRoot string,
	humanIntervened bool,
) uint64 {
	assert(agent != "", "empty agent id")
	assert(taskHash != "", "empty task hash")
	assert(outputCommitment != "", "empty output commitment")

	seq := uint64(len(receipts)) + 1
	r := &Receipt{
		Seq:              seq,
		Agent:            agent,
		TaskHash:         taskHash,
		InputCommitment:  inputCommitment,
		OutputCommitment: outputCommitment,
		RuntimeID:        runtimeID,
		PolicyVersion:    policyVersion,
		ToolCallsRoot:    toolCallsRoot,
		HumanIntervened:  humanIntervened,
		Author:           cur.Previous().Address(),
		Height:           runtime.ChainHeight(),
	}
	receipts = append(receipts, r)
	chain.Emit("ReceiptRecorded",
		"seq", ufmt.Sprintf("%d", seq),
		"agent", agent,
		"output", outputCommitment,
	)
	return seq
}

// Attest attaches an independent validator's verdict to a receipt. The same
// validator cannot attest twice; the author of a receipt cannot attest to
// their own work (self-attestation proves nothing).
func Attest(cur realm, seq uint64, verdict, note string) {
	r := mustGet(seq)
	validator := cur.Previous().Address()
	assert(validator != r.Author, "author cannot attest to their own receipt")
	assertVerdict(verdict)
	for _, a := range r.Attestations {
		assert(a.Validator != validator, "validator already attested")
	}
	r.Attestations = append(r.Attestations, Attestation{
		Validator: validator,
		Verdict:   verdict,
		Note:      note,
		Height:    runtime.ChainHeight(),
	})
	chain.Emit("ReceiptAttested",
		"seq", ufmt.Sprintf("%d", seq),
		"validator", validator.String(),
		"verdict", verdict,
	)
}

// ---- read-only API ----

// Get returns a copy of a receipt by sequence number.
func Get(seq uint64) Receipt { return *mustGet(seq) }

// Count returns the number of receipts recorded.
func Count() int { return len(receipts) }

// Confirmations returns (positive, rejections) attestation counts. It is a
// count of independent verdicts, deliberately NOT a truth value: a caller
// decides what threshold it trusts.
func Confirmations(seq uint64) (positive, rejections int) {
	for _, a := range mustGet(seq).Attestations {
		if a.Verdict == VerdictRejected {
			rejections++
		} else {
			positive++
		}
	}
	return positive, rejections
}

// ---- internal ----

func mustGet(seq uint64) *Receipt {
	assert(seq >= 1 && seq <= uint64(len(receipts)), "unknown receipt")
	return receipts[seq-1]
}

func assertVerdict(v string) {
	switch v {
	case VerdictReproduced, VerdictTestsPass, VerdictOutputMatch, VerdictPolicyOK, VerdictRejected:
		return
	}
	panic("unknown verdict: " + v)
}

func assert(cond bool, msg string) {
	if !cond {
		panic(msg)
	}
}

// Render shows the receipt log, or a single receipt at :<seq>.
func Render(path string) string {
	if path == "" {
		return renderIndex()
	}
	seq := parseSeq(path)
	return renderReceipt(seq)
}

func renderIndex() string {
	var sb strings.Builder
	sb.WriteString("# Agent Execution Receipts\n\n")
	sb.WriteString("_Provenance is not correctness._ Each row commits to an agent action; ")
	sb.WriteString("trust comes only from independent attestations.\n\n")
	if len(receipts) == 0 {
		sb.WriteString("_No receipts recorded yet._\n")
		return sb.String()
	}
	sb.WriteString("| # | Agent | Output commitment | Human? | ✅ | ❌ |\n")
	sb.WriteString("|---|---|---|---|---|---|\n")
	for _, r := range receipts {
		pos, rej := 0, 0
		for _, a := range r.Attestations {
			if a.Verdict == VerdictRejected {
				rej++
			} else {
				pos++
			}
		}
		human := "no"
		if r.HumanIntervened {
			human = "yes"
		}
		sb.WriteString(ufmt.Sprintf("| [%d](/r/g1manfred47kzduec920z88wfr64ylksmdcedlf5/agents/receipt:%d) | %s | `%s` | %s | %d | %d |\n",
			r.Seq, r.Seq, r.Agent, shortHash(r.OutputCommitment), human, pos, rej))
	}
	return sb.String()
}

func renderReceipt(seq uint64) string {
	r := mustGet(seq)
	var sb strings.Builder
	sb.WriteString(ufmt.Sprintf("# Receipt #%d\n\n", r.Seq))
	sb.WriteString(ufmt.Sprintf("- **Agent:** %s\n", r.Agent))
	sb.WriteString(ufmt.Sprintf("- **Author:** %s\n", r.Author.String()))
	sb.WriteString(ufmt.Sprintf("- **Recorded at height:** %d\n", r.Height))
	sb.WriteString(ufmt.Sprintf("- **Runtime:** %s\n", r.RuntimeID))
	sb.WriteString(ufmt.Sprintf("- **Policy version:** %s\n", r.PolicyVersion))
	sb.WriteString(ufmt.Sprintf("- **Human intervened:** %t\n\n", r.HumanIntervened))

	sb.WriteString("## Commitments\n\n")
	sb.WriteString("The realm stores only these hashes; the payloads live off-chain.\n\n")
	sb.WriteString(ufmt.Sprintf("- **Task:** `%s`\n", r.TaskHash))
	sb.WriteString(ufmt.Sprintf("- **Input:** `%s`\n", r.InputCommitment))
	sb.WriteString(ufmt.Sprintf("- **Output:** `%s`\n", r.OutputCommitment))
	sb.WriteString(ufmt.Sprintf("- **Tool-calls root:** `%s`\n\n", r.ToolCallsRoot))

	pos, rej := Confirmations(seq)
	sb.WriteString(ufmt.Sprintf("## Attestations (%d ✅ / %d ❌)\n\n", pos, rej))
	if len(r.Attestations) == 0 {
		sb.WriteString("> Unverified. This receipt proves the commitment above was made, nothing more.\n")
		return sb.String()
	}
	sb.WriteString("| Validator | Verdict | Note | Height |\n")
	sb.WriteString("|---|---|---|---|\n")
	for _, a := range r.Attestations {
		sb.WriteString(ufmt.Sprintf("| %s | %s | %s | %d |\n",
			shortHash(a.Validator.String()), a.Verdict, a.Note, a.Height))
	}
	return sb.String()
}

func parseSeq(s string) uint64 {
	var n uint64
	for i := 0; i < len(s); i++ {
		c := s[i]
		assert(c >= '0' && c <= '9', "invalid receipt path: "+s)
		n = n*10 + uint64(c-'0')
	}
	return n
}

func shortHash(s string) string {
	if len(s) <= 12 {
		return s
	}
	return s[:6] + "…" + s[len(s)-4:]
}

// Package gnomem is a shared, contestable memory for multiple agents.
//
// Most "agent memory" products store text and retrieve similar chunks.
// That works for one agent talking to itself. It breaks the moment several
// independent agents — possibly run by different people, on different
// models — must maintain a *shared* understanding of the same world and
// sometimes disagree about it.
//
// gnomem models memory not as text but as a graph of structured claims.
// Each claim is a (subject, predicate, object) triple with an author,
// evidence and a confidence. Other agents can support it, contest it, add
// evidence, supersede it with a better claim, or trigger adjudication. No
// agent can silently erase an inconvenient finding: claims can be
// superseded or retracted, but the history stays visible and ordered.
//
// The point of the demo is the structure, not access control: anyone may
// write. Gating *who* may write to which claim is exactly what the
// capability-wallet demo adds on top.
package gnomem

import (
	"chain"
	"chain/runtime"
	"strings"

	"gno.land/p/nt/ufmt/v0"
)

// Status is a claim's position in the argument lifecycle.
type Status string

const (
	StatusProposed   Status = "proposed"   // asserted, no endorsements yet
	StatusSupported  Status = "supported"  // has support, no live contest
	StatusContested  Status = "contested"  // at least one live contest
	StatusAccepted   Status = "accepted"   // adjudicated true (terminal)
	StatusRetracted  Status = "retracted"  // adjudicated false / withdrawn (terminal)
	StatusSuperseded Status = "superseded" // replaced by a better claim (terminal)
)

// Endorsement is a support or contest signal from one agent.
type Endorsement struct {
	Agent      address
	Confidence uint8 // 0..100
	Note       string
	Height     int64
}

// Evidence points at off-chain material backing (or refuting) a claim.
type Evidence struct {
	By     address
	Kind   string // "report", "exploit", "dataset", "citation", ...
	Hash   string // commitment to the off-chain artifact
	Height int64
}

// Claim is one node in the shared memory graph.
type Claim struct {
	ID           uint64
	Subject      string
	Predicate    string
	Object       string
	Author       address
	Confidence   uint8
	Status       Status
	CreatedAt    int64
	Supports     []Endorsement
	Contests     []Endorsement
	Evidence     []Evidence
	SupersededBy uint64 // 0 if none
	Supersedes   uint64 // 0 if none
	Resolver     address
	ResolvedAt   int64
}

var claims []*Claim // index 0 => ID 1

// ProposeClaim asserts a new (subject, predicate, object) triple.
func ProposeClaim(cur realm, subject, predicate, object, evidenceHash string, confidence uint8) uint64 {
	assert(subject != "" && predicate != "" && object != "", "empty triple field")
	assertConfidence(confidence)

	id := uint64(len(claims)) + 1
	c := &Claim{
		ID:         id,
		Subject:    subject,
		Predicate:  predicate,
		Object:     object,
		Author:     cur.Previous().Address(),
		Confidence: confidence,
		Status:     StatusProposed,
		CreatedAt:  runtime.ChainHeight(),
	}
	if evidenceHash != "" {
		c.Evidence = append(c.Evidence, Evidence{
			By: c.Author, Kind: "initial", Hash: evidenceHash, Height: c.CreatedAt,
		})
	}
	claims = append(claims, c)
	chain.Emit("ClaimProposed", "id", ufmt.Sprintf("%d", id), "subject", subject, "predicate", predicate)
	return id
}

// SupportClaim endorses a claim. Support never overrides a live contest —
// a contested claim stays contested until adjudicated.
func SupportClaim(cur realm, id uint64, confidence uint8, note string) {
	c := mustOpen(id)
	assertConfidence(confidence)
	c.Supports = append(c.Supports, Endorsement{
		Agent: cur.Previous().Address(), Confidence: confidence, Note: note, Height: runtime.ChainHeight(),
	})
	if c.Status == StatusProposed {
		c.Status = StatusSupported
	}
	chain.Emit("ClaimSupported", "id", ufmt.Sprintf("%d", id))
}

// ContestClaim challenges a claim, optionally attaching refuting evidence.
func ContestClaim(cur realm, id uint64, note, evidenceHash string) {
	c := mustOpen(id)
	agent := cur.Previous().Address()
	h := runtime.ChainHeight()
	c.Contests = append(c.Contests, Endorsement{
		Agent: agent, Confidence: 0, Note: note, Height: h,
	})
	if evidenceHash != "" {
		c.Evidence = append(c.Evidence, Evidence{By: agent, Kind: "refutation", Hash: evidenceHash, Height: h})
	}
	c.Status = StatusContested
	chain.Emit("ClaimContested", "id", ufmt.Sprintf("%d", id))
}

// AddEvidence attaches supporting or contextual off-chain material.
func AddEvidence(cur realm, id uint64, kind, hash string) {
	c := mustOpen(id)
	assert(hash != "", "empty evidence hash")
	c.Evidence = append(c.Evidence, Evidence{
		By: cur.Previous().Address(), Kind: kind, Hash: hash, Height: runtime.ChainHeight(),
	})
}

// SupersedeClaim replaces an open claim with a new one. The old claim is
// marked superseded (terminal) and linked to its replacement, so the
// correction is visible rather than a silent overwrite.
func SupersedeClaim(cur realm, oldID uint64, subject, predicate, object, evidenceHash string, confidence uint8) uint64 {
	old := mustOpen(oldID)
	newID := ProposeClaim(cur, subject, predicate, object, evidenceHash, confidence)
	newC := claims[newID-1]
	newC.Supersedes = oldID
	old.Status = StatusSuperseded
	old.SupersededBy = newID
	chain.Emit("ClaimSuperseded", "old", ufmt.Sprintf("%d", oldID), "new", ufmt.Sprintf("%d", newID))
	return newID
}

// ResolveClaim adjudicates an open claim as accepted (true) or retracted
// (false/withdrawn). The resolver's address is recorded — resolution is
// itself a provenance-bearing act, not an anonymous verdict.
func ResolveClaim(cur realm, id uint64, accepted bool) {
	c := mustOpen(id)
	if accepted {
		c.Status = StatusAccepted
	} else {
		c.Status = StatusRetracted
	}
	c.Resolver = cur.Previous().Address()
	c.ResolvedAt = runtime.ChainHeight()
	chain.Emit("ClaimResolved", "id", ufmt.Sprintf("%d", id), "status", string(c.Status))
}

// ---- read-only API ----

// Get returns a copy of a claim by id.
func Get(id uint64) Claim { return *mustGet(id) }

// Count returns the number of claims in the graph.
func Count() int { return len(claims) }

// IsOpen reports whether a claim can still be supported/contested/resolved.
func IsOpen(id uint64) bool { return isOpen(mustGet(id).Status) }

// ---- internal ----

func isOpen(s Status) bool {
	return s == StatusProposed || s == StatusSupported || s == StatusContested
}

func mustGet(id uint64) *Claim {
	assert(id >= 1 && id <= uint64(len(claims)), "unknown claim")
	return claims[id-1]
}

func mustOpen(id uint64) *Claim {
	c := mustGet(id)
	assert(isOpen(c.Status), "claim is resolved (terminal): "+string(c.Status))
	return c
}

func assertConfidence(c uint8) { assert(c <= 100, "confidence must be 0..100") }

func assert(cond bool, msg string) {
	if !cond {
		panic(msg)
	}
}

// Render shows the full graph, or one claim's argument tree at :<id>.
func Render(path string) string {
	if path == "" {
		return renderIndex()
	}
	return renderClaim(parseID(path))
}

func renderIndex() string {
	var sb strings.Builder
	sb.WriteString("# GnoMem — Contested Shared Memory\n\n")
	sb.WriteString(ufmt.Sprintf("A graph of %d structured claim(s) maintained by multiple agents.\n\n", len(claims)))
	if len(claims) == 0 {
		sb.WriteString("_No claims yet._\n")
		return sb.String()
	}
	sb.WriteString("| # | Claim | Status | ✋ support | ⚔ contest |\n")
	sb.WriteString("|---|---|---|---|---|\n")
	for _, c := range claims {
		sb.WriteString(ufmt.Sprintf("| [%d](/r/g1manfred47kzduec920z88wfr64ylksmdcedlf5/agents/gnomem:%d) | %s | %s | %d | %d |\n",
			c.ID, c.ID, triple(c), statusBadge(c.Status), len(c.Supports), len(c.Contests)))
	}
	return sb.String()
}

func renderClaim(id uint64) string {
	c := mustGet(id)
	var sb strings.Builder
	sb.WriteString(ufmt.Sprintf("# Claim #%d\n\n", c.ID))
	sb.WriteString(ufmt.Sprintf("> **%s**\n\n", triple(c)))
	sb.WriteString(ufmt.Sprintf("- **Status:** %s\n", statusBadge(c.Status)))
	sb.WriteString(ufmt.Sprintf("- **Author:** %s\n", short(c.Author)))
	sb.WriteString(ufmt.Sprintf("- **Author confidence:** %d/100\n", c.Confidence))
	sb.WriteString(ufmt.Sprintf("- **Created at height:** %d\n", c.CreatedAt))
	if c.Supersedes != 0 {
		sb.WriteString(ufmt.Sprintf("- **Supersedes:** [#%d](/r/g1manfred47kzduec920z88wfr64ylksmdcedlf5/agents/gnomem:%d)\n", c.Supersedes, c.Supersedes))
	}
	if c.SupersededBy != 0 {
		sb.WriteString(ufmt.Sprintf("- **Superseded by:** [#%d](/r/g1manfred47kzduec920z88wfr64ylksmdcedlf5/agents/gnomem:%d)\n", c.SupersededBy, c.SupersededBy))
	}
	if c.ResolvedAt != 0 {
		sb.WriteString(ufmt.Sprintf("- **Resolved by:** %s at height %d\n", short(c.Resolver), c.ResolvedAt))
	}
	sb.WriteString("\n")

	sb.WriteString(ufmt.Sprintf("## ✋ Support (%d)\n\n", len(c.Supports)))
	renderEndorsements(&sb, c.Supports)
	sb.WriteString(ufmt.Sprintf("## ⚔ Contest (%d)\n\n", len(c.Contests)))
	renderEndorsements(&sb, c.Contests)

	sb.WriteString(ufmt.Sprintf("## 📎 Evidence (%d)\n\n", len(c.Evidence)))
	if len(c.Evidence) == 0 {
		sb.WriteString("_None._\n")
	} else {
		sb.WriteString("| By | Kind | Commitment | Height |\n|---|---|---|---|\n")
		for _, e := range c.Evidence {
			sb.WriteString(ufmt.Sprintf("| %s | %s | `%s` | %d |\n", short(e.By), e.Kind, shortHash(e.Hash), e.Height))
		}
	}
	return sb.String()
}

func renderEndorsements(sb *strings.Builder, es []Endorsement) {
	if len(es) == 0 {
		sb.WriteString("_None._\n\n")
		return
	}
	sb.WriteString("| Agent | Confidence | Note | Height |\n|---|---|---|---|\n")
	for _, e := range es {
		sb.WriteString(ufmt.Sprintf("| %s | %d | %s | %d |\n", short(e.Agent), e.Confidence, e.Note, e.Height))
	}
	sb.WriteString("\n")
}

func triple(c *Claim) string {
	return ufmt.Sprintf("%s — %s — %s", c.Subject, c.Predicate, c.Object)
}

func statusBadge(s Status) string {
	switch s {
	case StatusAccepted:
		return "✅ accepted"
	case StatusRetracted:
		return "🚫 retracted"
	case StatusSuperseded:
		return "♻️ superseded"
	case StatusContested:
		return "⚔ contested"
	case StatusSupported:
		return "✋ supported"
	default:
		return "· proposed"
	}
}

func parseID(s string) uint64 {
	var n uint64
	for i := 0; i < len(s); i++ {
		c := s[i]
		assert(c >= '0' && c <= '9', "invalid claim path: "+s)
		n = n*10 + uint64(c-'0')
	}
	return n
}

func short(a address) string {
	s := a.String()
	if len(s) <= 12 {
		return s
	}
	return s[:8] + "…" + s[len(s)-4:]
}

func shortHash(s string) string {
	if len(s) <= 12 {
		return s
	}
	return s[:6] + "…" + s[len(s)-4:]
}

// Package capwallet issues narrow, bounded, revocable capabilities to
// agents — instead of handing an agent a wallet key and hoping its prompt
// stays safe.
//
// The demo makes three ideas that are usually conflated stand apart:
//
//   - identity      — "this is agent Percy"
//   - authorization — "Percy may call this function on this realm"
//   - approval      — "Percy may do it at most N times, for ≤ M coins,
//                      before block H, and I can revoke it at any moment"
//
// A capability is the third thing: a least-privilege grant with a ceiling,
// an expiry, a use counter and a kill switch. Other realms consult
// Authorized() before honoring an agent action; the granter revokes with
// one call the instant something looks wrong.
package capwallet

import (
	"chain"
	"chain/runtime"
	"strings"

	"gno.land/p/nt/ufmt/v0"
)

// Use records one exercise of a capability.
type Use struct {
	By     address
	Coins  int64
	Height int64
}

// Capability is a least-privilege grant from a granter to a principal.
type Capability struct {
	ID            uint64
	Granter       address
	Principal     address // the only address that may exercise it
	TargetRealm   string  // realm the capability is scoped to
	Function      string  // function the capability authorizes
	MaxCoins      int64   // per-exercise ceiling in ugnot (0 = none allowed)
	ValidUntil    int64   // block height after which it expires (0 = never)
	RemainingUses uint32  // exercises left (0 = exhausted)
	ArgsPolicy    string  // human-readable note on allowed arguments
	Revoked       bool
	GrantedAt     int64
	Uses          []Use
}

var caps []*Capability // index 0 => ID 1

// Grant issues a capability. The caller becomes its granter and can revoke
// it later. validUntil is an absolute block height (0 = no expiry).
func Grant(
	cur realm,
	principal address,
	targetRealm, function string,
	maxCoins, validUntil int64,
	uses uint32,
	argsPolicy string,
) uint64 {
	assert(targetRealm != "" && function != "", "target realm and function required")
	assert(uses > 0, "must grant at least one use")

	id := uint64(len(caps)) + 1
	c := &Capability{
		ID:            id,
		Granter:       cur.Previous().Address(),
		Principal:     principal,
		TargetRealm:   targetRealm,
		Function:      function,
		MaxCoins:      maxCoins,
		ValidUntil:    validUntil,
		RemainingUses: uses,
		ArgsPolicy:    argsPolicy,
		GrantedAt:     runtime.ChainHeight(),
	}
	caps = append(caps, c)
	chain.Emit("CapabilityGranted",
		"id", ufmt.Sprintf("%d", id),
		"principal", principal.String(),
		"target", targetRealm+"."+function,
	)
	return id
}

// Exercise consumes one use of a capability. Only the principal may call it,
// and every bound is checked: not revoked, not expired, uses remaining, and
// coins within the ceiling. On success the use is recorded and the counter
// decremented.
func Exercise(cur realm, id uint64, coins int64) {
	c := mustGet(id)
	caller := cur.Previous().Address()
	assert(caller == c.Principal, "caller is not the capability principal")
	assertUsable(c)
	assert(coins <= c.MaxCoins, ufmt.Sprintf("coins %d exceed capability ceiling %d", coins, c.MaxCoins))

	c.RemainingUses--
	c.Uses = append(c.Uses, Use{By: caller, Coins: coins, Height: runtime.ChainHeight()})
	chain.Emit("CapabilityExercised",
		"id", ufmt.Sprintf("%d", id),
		"coins", ufmt.Sprintf("%d", coins),
		"remaining", ufmt.Sprintf("%d", c.RemainingUses),
	)
}

// Revoke disables a capability immediately. Only the granter may revoke.
func Revoke(cur realm, id uint64) {
	c := mustGet(id)
	assert(cur.Previous().Address() == c.Granter, "only the granter may revoke")
	c.Revoked = true
	chain.Emit("CapabilityRevoked", "id", ufmt.Sprintf("%d", id))
}

// ---- read-only API for gating realms ----

// Authorized reports whether principal may exercise capability id for the
// given coin amount right now — the check a target realm runs before acting.
// It never mutates state or consumes a use.
func Authorized(id uint64, principal address, coins int64) bool {
	if id < 1 || id > uint64(len(caps)) {
		return false
	}
	c := caps[id-1]
	if c.Principal != principal || !usable(c) {
		return false
	}
	return coins <= c.MaxCoins
}

// Get returns a copy of a capability.
func Get(id uint64) Capability { return *mustGet(id) }

// Count returns the number of capabilities issued.
func Count() int { return len(caps) }

// ---- internal ----

func usable(c *Capability) bool {
	if c.Revoked || c.RemainingUses == 0 {
		return false
	}
	if c.ValidUntil != 0 && runtime.ChainHeight() > c.ValidUntil {
		return false
	}
	return true
}

func assertUsable(c *Capability) {
	assert(!c.Revoked, "capability revoked")
	assert(c.RemainingUses > 0, "capability exhausted")
	assert(c.ValidUntil == 0 || runtime.ChainHeight() <= c.ValidUntil, "capability expired")
}

func mustGet(id uint64) *Capability {
	assert(id >= 1 && id <= uint64(len(caps)), "unknown capability")
	return caps[id-1]
}

func assert(cond bool, msg string) {
	if !cond {
		panic(msg)
	}
}

// Render shows all capabilities, or one capability's detail + usage at :<id>.
func Render(path string) string {
	if path == "" {
		return renderIndex()
	}
	return renderCap(parseID(path))
}

func renderIndex() string {
	var sb strings.Builder
	sb.WriteString("# Capability Wallet\n\n")
	sb.WriteString("_Don't give an agent a wallet. Give it a capability._\n\n")
	if len(caps) == 0 {
		sb.WriteString("_No capabilities granted yet._\n")
		return sb.String()
	}
	sb.WriteString("| # | Principal | Scope | Ceiling | Uses left | State |\n")
	sb.WriteString("|---|---|---|---|---|---|\n")
	for _, c := range caps {
		sb.WriteString(ufmt.Sprintf("| [%d](/r/g1manfred47kzduec920z88wfr64ylksmdcedlf5/agents/capwallet:%d) | %s | `%s.%s` | %d ugnot | %d | %s |\n",
			c.ID, c.ID, short(c.Principal), c.TargetRealm, c.Function, c.MaxCoins, c.RemainingUses, state(c)))
	}
	return sb.String()
}

func renderCap(id uint64) string {
	c := mustGet(id)
	var sb strings.Builder
	sb.WriteString(ufmt.Sprintf("# Capability #%d\n\n", c.ID))
	sb.WriteString(ufmt.Sprintf("- **State:** %s\n", state(c)))
	sb.WriteString(ufmt.Sprintf("- **Granter:** %s\n", c.Granter.String()))
	sb.WriteString(ufmt.Sprintf("- **Principal:** %s\n", c.Principal.String()))
	sb.WriteString(ufmt.Sprintf("- **Scope:** `%s.%s`\n", c.TargetRealm, c.Function))
	sb.WriteString(ufmt.Sprintf("- **Per-use ceiling:** %d ugnot\n", c.MaxCoins))
	if c.ValidUntil == 0 {
		sb.WriteString("- **Expires:** never\n")
	} else {
		sb.WriteString(ufmt.Sprintf("- **Expires at height:** %d (now %d)\n", c.ValidUntil, runtime.ChainHeight()))
	}
	sb.WriteString(ufmt.Sprintf("- **Uses remaining:** %d\n", c.RemainingUses))
	sb.WriteString(ufmt.Sprintf("- **Args policy:** %s\n\n", c.ArgsPolicy))

	sb.WriteString(ufmt.Sprintf("## Exercise log (%d)\n\n", len(c.Uses)))
	if len(c.Uses) == 0 {
		sb.WriteString("_Never exercised._\n")
		return sb.String()
	}
	sb.WriteString("| By | Coins | Height |\n|---|---|---|\n")
	for _, u := range c.Uses {
		sb.WriteString(ufmt.Sprintf("| %s | %d | %d |\n", short(u.By), u.Coins, u.Height))
	}
	return sb.String()
}

func state(c *Capability) string {
	if c.Revoked {
		return "🚫 revoked"
	}
	if c.RemainingUses == 0 {
		return "· exhausted"
	}
	if c.ValidUntil != 0 && runtime.ChainHeight() > c.ValidUntil {
		return "⏳ expired"
	}
	return "✅ live"
}

func parseID(s string) uint64 {
	var n uint64
	for i := 0; i < len(s); i++ {
		ch := s[i]
		assert(ch >= '0' && ch <= '9', "invalid capability path: "+s)
		n = n*10 + uint64(ch-'0')
	}
	return n
}

func short(a address) string {
	s := a.String()
	if len(s) <= 12 {
		return s
	}
	return s[:8] + "…" + s[len(s)-4:]
}

// Package jury is a commit-reveal adversarial review protocol for disputes
// over agent work.
//
// The hard part of an agent economy is not paying agents — it is deciding
// what happens when an agent's output is disputed. This realm runs a small
// jury: a fixed panel of reviewers each *commit* to a hidden verdict, then
// *reveal* it. Commit-reveal means no juror can copy another's vote or be
// swayed after seeing the tally; every verdict is locked in blind.
//
// The subject of a case is an opaque string — a receipt sequence, a claim
// id, an off-chain artifact hash — so this realm composes with the receipt
// and gnomem demos without depending on them.
//
// Bonding and slashing (a juror stakes coins, loses them for provably bad
// verdicts) are the natural economic layer on top; this demo shows the
// mechanism without the money.
package jury

import (
	"chain"
	"chain/runtime"
	"strings"

	"gno.land/p/g1manfred47kzduec920z88wfr64ylksmdcedlf5/agents/commit"
	"gno.land/p/nt/ufmt/v0"
)

// Phase is a case's position in the commit-reveal lifecycle.
type Phase string

const (
	PhaseCommit Phase = "commit"
	PhaseReveal Phase = "reveal"
	PhaseClosed Phase = "closed"
)

// Juror is one panelist and their (eventually revealed) verdict.
type Juror struct {
	Addr       address
	Commitment string // commit.Verdict(verdict, salt)
	Committed  bool
	Revealed   bool
	Verdict    bool // meaningful once Revealed
	Height     int64
}

// Case is a single dispute under review by a fixed panel.
type Case struct {
	ID       uint64
	Subject  string // opaque reference to the disputed thing
	Opener   address
	Phase    Phase
	Jurors   []*Juror
	OpenedAt int64
	Outcome  string // "upheld" | "rejected" | "tie" once closed
	Yes      int
	No       int
}

var cases []*Case // index 0 => ID 1

// OpenCase starts a dispute with a fixed panel of jurors. An odd panel size
// avoids ties; duplicates are rejected.
func OpenCase(cur realm, subject string, jurors []address) uint64 {
	assert(subject != "", "empty subject")
	assert(len(jurors) >= 1, "need at least one juror")

	seen := make(map[string]bool)
	panel := make([]*Juror, 0, len(jurors))
	for _, j := range jurors {
		key := j.String()
		assert(!seen[key], "duplicate juror: "+key)
		seen[key] = true
		panel = append(panel, &Juror{Addr: j})
	}

	id := uint64(len(cases)) + 1
	cases = append(cases, &Case{
		ID:       id,
		Subject:  subject,
		Opener:   cur.Previous().Address(),
		Phase:    PhaseCommit,
		Jurors:   panel,
		OpenedAt: runtime.ChainHeight(),
	})
	chain.Emit("CaseOpened", "id", ufmt.Sprintf("%d", id), "jurors", ufmt.Sprintf("%d", len(panel)))
	return id
}

// Commit locks in a juror's hidden verdict. commitment must equal
// commit.Verdict(verdict, salt) — computed off-chain. When the last juror
// commits, the case advances to the reveal phase automatically.
func Commit(cur realm, caseID uint64, commitment string) {
	c := mustCase(caseID)
	assert(c.Phase == PhaseCommit, "not in commit phase")
	assert(commitment != "", "empty commitment")
	j := mustJuror(c, cur.Previous().Address())
	assert(!j.Committed, "already committed")
	j.Commitment = commitment
	j.Committed = true
	j.Height = runtime.ChainHeight()

	if allCommitted(c) {
		c.Phase = PhaseReveal
		chain.Emit("CasePhase", "id", ufmt.Sprintf("%d", caseID), "phase", string(PhaseReveal))
	}
}

// Reveal opens a juror's verdict. The (verdict, salt) must reproduce the
// commitment made earlier, or the reveal is rejected. When the last juror
// reveals, the case closes and the majority outcome is recorded.
func Reveal(cur realm, caseID uint64, verdict bool, salt string) {
	c := mustCase(caseID)
	assert(c.Phase == PhaseReveal, "not in reveal phase")
	j := mustJuror(c, cur.Previous().Address())
	assert(j.Committed && !j.Revealed, "nothing to reveal")
	assert(commit.Verdict(verdict, salt) == j.Commitment, "reveal does not match commitment")

	j.Revealed = true
	j.Verdict = verdict
	if verdict {
		c.Yes++
	} else {
		c.No++
	}
	chain.Emit("VerdictRevealed", "id", ufmt.Sprintf("%d", caseID), "verdict", boolStr(verdict))

	if allRevealed(c) {
		closeCase(c)
	}
}

// ---- read-only API ----

// Get returns a copy of a case (jurors flattened separately via Jury).
func Get(caseID uint64) Case { return *mustCase(caseID) }

// Outcome returns the recorded outcome, or "" if the case is still open.
func Outcome(caseID uint64) string { return mustCase(caseID).Outcome }

// Count returns the number of cases.
func Count() int { return len(cases) }

// ---- internal ----

func closeCase(c *Case) {
	switch {
	case c.Yes > c.No:
		c.Outcome = "upheld"
	case c.No > c.Yes:
		c.Outcome = "rejected"
	default:
		c.Outcome = "tie"
	}
	c.Phase = PhaseClosed
	chain.Emit("CaseClosed", "id", ufmt.Sprintf("%d", c.ID), "outcome", c.Outcome)
}

func allCommitted(c *Case) bool {
	for _, j := range c.Jurors {
		if !j.Committed {
			return false
		}
	}
	return true
}

func allRevealed(c *Case) bool {
	for _, j := range c.Jurors {
		if !j.Revealed {
			return false
		}
	}
	return true
}

func mustCase(id uint64) *Case {
	assert(id >= 1 && id <= uint64(len(cases)), "unknown case")
	return cases[id-1]
}

func mustJuror(c *Case, addr address) *Juror {
	for _, j := range c.Jurors {
		if j.Addr == addr {
			return j
		}
	}
	panic("caller is not on this jury")
}

func boolStr(b bool) string {
	if b {
		return "yes"
	}
	return "no"
}

func assert(cond bool, msg string) {
	if !cond {
		panic(msg)
	}
}

// Render shows all cases, or one case's panel + tally at :<id>.
func Render(path string) string {
	if path == "" {
		return renderIndex()
	}
	return renderCase(parseID(path))
}

func renderIndex() string {
	var sb strings.Builder
	sb.WriteString("# Agent Jury\n\n")
	sb.WriteString("_Who checks the agents?_ Blind commit-reveal review by a fixed panel.\n\n")
	if len(cases) == 0 {
		sb.WriteString("_No cases yet._\n")
		return sb.String()
	}
	sb.WriteString("| # | Subject | Phase | ✅ | ❌ | Outcome |\n")
	sb.WriteString("|---|---|---|---|---|---|\n")
	for _, c := range cases {
		out := c.Outcome
		if out == "" {
			out = "—"
		}
		sb.WriteString(ufmt.Sprintf("| [%d](/r/g1manfred47kzduec920z88wfr64ylksmdcedlf5/agents/jury:%d) | %s | %s | %d | %d | %s |\n",
			c.ID, c.ID, c.Subject, string(c.Phase), c.Yes, c.No, out))
	}
	return sb.String()
}

func renderCase(id uint64) string {
	c := mustCase(id)
	var sb strings.Builder
	sb.WriteString(ufmt.Sprintf("# Case #%d\n\n", c.ID))
	sb.WriteString(ufmt.Sprintf("- **Subject:** %s\n", c.Subject))
	sb.WriteString(ufmt.Sprintf("- **Phase:** %s\n", string(c.Phase)))
	sb.WriteString(ufmt.Sprintf("- **Opened by:** %s at height %d\n", short(c.Opener), c.OpenedAt))
	if c.Outcome != "" {
		sb.WriteString(ufmt.Sprintf("- **Outcome:** **%s** (%d ✅ / %d ❌)\n", c.Outcome, c.Yes, c.No))
	}
	sb.WriteString("\n## Panel\n\n")
	sb.WriteString("| Juror | Committed | Revealed | Verdict | Dissent |\n|---|---|---|---|---|\n")
	majority := c.Yes >= c.No // for dissent marking once closed
	for _, j := range c.Jurors {
		verdict, dissent := "—", ""
		if j.Revealed {
			verdict = boolStr(j.Verdict)
			if c.Phase == PhaseClosed && c.Outcome != "tie" && j.Verdict != majority {
				dissent = "⚠"
			}
		}
		sb.WriteString(ufmt.Sprintf("| %s | %t | %t | %s | %s |\n",
			short(j.Addr), j.Committed, j.Revealed, verdict, dissent))
	}
	return sb.String()
}

func parseID(s string) uint64 {
	var n uint64
	for i := 0; i < len(s); i++ {
		ch := s[i]
		assert(ch >= '0' && ch <= '9', "invalid case path: "+s)
		n = n*10 + uint64(ch-'0')
	}
	return n
}

func short(a address) string {
	s := a.String()
	if len(s) <= 12 {
		return s
	}
	return s[:8] + "…" + s[len(s)-4:]
}

// Package maintainer models an AI agent stewarding a versioned on-chain
// package — without ever letting it deploy on its own authority.
//
// The agent can do the tedious, valuable parts: open a version proposal,
// collect reviews, record CI test attestations, write release notes,
// deprecate a vulnerable version, keep a compatibility matrix. What it
// cannot do is ship. Approval is gated by an explicit, machine-checked
// policy:
//
//	tests pass  AND  ≥ MinReviewers independent reviews  AND
//	every review scores ≥ MinScore  AND  the challenge window has elapsed
//
// This is the difference between "an agent with commit access" and "an
// agent that drives a process a human (or a DAO, or a policy) still gates."
// The realm records *approved* releases; the actual package publish is a
// separate, deliberately human/authority step.
package maintainer

import (
	"chain"
	"chain/runtime"
	"strings"

	"gno.land/p/nt/ufmt/v0"
)

const (
	MinReviewers = 2  // independent reviews required
	MinScore     = 80 // minimum score every reviewer must give
)

// Review is one reviewer's score for a proposal.
type Review struct {
	By     address
	Score  uint8 // 0..100
	Note   string
	Height int64
}

// Proposal is a candidate new version working its way toward approval.
type Proposal struct {
	ID             uint64
	Version        string
	ArtifactHash   string // commitment to the package source
	Proposer       address
	Reviews        []Review
	TestsPass      bool
	TestsAttestor  address
	OpenedAt       int64
	ChallengeUntil int64 // approval blocked until height passes this
	Approved       bool
	ApprovedAt     int64
}

// Release is an approved (and possibly later deprecated) version.
type Release struct {
	Version          string
	ArtifactHash     string
	ReleasedAt       int64
	Deprecated       bool
	DeprecatedReason string
}

var (
	proposals []*Proposal        // index 0 => ID 1
	releases  []*Release         // in release order
	byVersion = map[string]*Release{}
)

// Propose opens a version proposal with a challenge window of the given
// number of blocks (during which reviews accrue and approval is blocked).
func Propose(cur realm, version, artifactHash string, challengeBlocks int64) uint64 {
	assert(version != "", "empty version")
	assert(artifactHash != "", "empty artifact hash")
	assert(challengeBlocks >= 0, "negative challenge window")
	_, exists := byVersion[version]
	assert(!exists, "version already released: "+version)

	id := uint64(len(proposals)) + 1
	h := runtime.ChainHeight()
	proposals = append(proposals, &Proposal{
		ID:             id,
		Version:        version,
		ArtifactHash:   artifactHash,
		Proposer:       cur.Previous().Address(),
		OpenedAt:       h,
		ChallengeUntil: h + challengeBlocks,
	})
	chain.Emit("VersionProposed", "id", ufmt.Sprintf("%d", id), "version", version)
	return id
}

// AddReview records a reviewer's score. Reviewers must be independent of the
// proposer, and each address reviews at most once.
func AddReview(cur realm, propID uint64, score uint8, note string) {
	p := mustProposal(propID)
	assert(!p.Approved, "proposal already approved")
	assert(score <= 100, "score must be 0..100")
	reviewer := cur.Previous().Address()
	assert(reviewer != p.Proposer, "proposer cannot review own proposal")
	for _, r := range p.Reviews {
		assert(r.By != reviewer, "reviewer already reviewed")
	}
	p.Reviews = append(p.Reviews, Review{By: reviewer, Score: score, Note: note, Height: runtime.ChainHeight()})
	chain.Emit("VersionReviewed", "id", ufmt.Sprintf("%d", propID), "score", ufmt.Sprintf("%d", score))
}

// AttestTests records whether CI's test suite passed for the proposal.
func AttestTests(cur realm, propID uint64, pass bool) {
	p := mustProposal(propID)
	assert(!p.Approved, "proposal already approved")
	p.TestsPass = pass
	p.TestsAttestor = cur.Previous().Address()
	chain.Emit("TestsAttested", "id", ufmt.Sprintf("%d", propID), "pass", boolStr(pass))
}

// Approve promotes a proposal to a release iff every policy condition holds.
// It panics with the first unmet condition — the policy is the gate, not a
// suggestion.
func Approve(cur realm, propID uint64) {
	p := mustProposal(propID)
	assert(!p.Approved, "proposal already approved")
	assert(p.TestsPass, "policy: tests have not passed")
	assert(len(p.Reviews) >= MinReviewers, ufmt.Sprintf("policy: need %d reviews, have %d", MinReviewers, len(p.Reviews)))
	for _, r := range p.Reviews {
		assert(r.Score >= MinScore, ufmt.Sprintf("policy: review from %s scored %d < %d", short(r.By), r.Score, MinScore))
	}
	assert(runtime.ChainHeight() > p.ChallengeUntil, "policy: challenge window still open")

	p.Approved = true
	p.ApprovedAt = runtime.ChainHeight()
	rel := &Release{Version: p.Version, ArtifactHash: p.ArtifactHash, ReleasedAt: p.ApprovedAt}
	releases = append(releases, rel)
	byVersion[p.Version] = rel
	chain.Emit("VersionApproved", "id", ufmt.Sprintf("%d", propID), "version", p.Version)
}

// Deprecate flags a released version (e.g. a vulnerability was found).
func Deprecate(cur realm, version, reason string) {
	rel, ok := byVersion[version]
	assert(ok, "unknown version: "+version)
	rel.Deprecated = true
	rel.DeprecatedReason = reason
	chain.Emit("VersionDeprecated", "version", version)
}

// ---- read-only API ----

// LatestVersion returns the most recently released version, or "".
func LatestVersion() string {
	if len(releases) == 0 {
		return ""
	}
	return releases[len(releases)-1].Version
}

// IsDeprecated reports whether a released version is deprecated.
func IsDeprecated(version string) bool {
	rel, ok := byVersion[version]
	return ok && rel.Deprecated
}

// GetProposal returns a copy of a proposal.
func GetProposal(id uint64) Proposal { return *mustProposal(id) }

// ---- internal ----

func mustProposal(id uint64) *Proposal {
	assert(id >= 1 && id <= uint64(len(proposals)), "unknown proposal")
	return proposals[id-1]
}

func boolStr(b bool) string {
	if b {
		return "yes"
	}
	return "no"
}

func assert(cond bool, msg string) {
	if !cond {
		panic(msg)
	}
}

// Render shows the release matrix + open proposals, or one proposal at :<id>.
func Render(path string) string {
	if path == "" {
		return renderIndex()
	}
	return renderProposal(parseID(path))
}

func renderIndex() string {
	var sb strings.Builder
	sb.WriteString("# Agent Package Maintainer\n\n")
	sb.WriteString(ufmt.Sprintf("_The agent drives the process; the policy still gates the ship._ "))
	sb.WriteString(ufmt.Sprintf("Approval needs tests + ≥%d reviews each ≥%d + an elapsed challenge window.\n\n", MinReviewers, MinScore))

	sb.WriteString("## Releases\n\n")
	if len(releases) == 0 {
		sb.WriteString("_No releases yet._\n\n")
	} else {
		sb.WriteString("| Version | Released @ | State |\n|---|---|---|\n")
		for _, r := range releases {
			st := "✅ current"
			if r.Deprecated {
				st = "⚠ deprecated: " + r.DeprecatedReason
			}
			sb.WriteString(ufmt.Sprintf("| %s | %d | %s |\n", r.Version, r.ReleasedAt, st))
		}
		sb.WriteString("\n")
	}

	sb.WriteString("## Proposals\n\n")
	if len(proposals) == 0 {
		sb.WriteString("_None._\n")
		return sb.String()
	}
	sb.WriteString("| # | Version | Tests | Reviews | Approved |\n|---|---|---|---|---|\n")
	for _, p := range proposals {
		sb.WriteString(ufmt.Sprintf("| [%d](/r/g1manfred47kzduec920z88wfr64ylksmdcedlf5/agents/maintainer:%d) | %s | %s | %d | %t |\n",
			p.ID, p.ID, p.Version, boolStr(p.TestsPass), len(p.Reviews), p.Approved))
	}
	return sb.String()
}

func renderProposal(id uint64) string {
	p := mustProposal(id)
	var sb strings.Builder
	sb.WriteString(ufmt.Sprintf("# Proposal #%d — %s\n\n", p.ID, p.Version))
	sb.WriteString(ufmt.Sprintf("- **Artifact:** `%s`\n", shortHash(p.ArtifactHash)))
	sb.WriteString(ufmt.Sprintf("- **Proposer:** %s\n", short(p.Proposer)))
	sb.WriteString(ufmt.Sprintf("- **Tests pass:** %t\n", p.TestsPass))
	sb.WriteString(ufmt.Sprintf("- **Challenge window until height:** %d (now %d)\n", p.ChallengeUntil, runtime.ChainHeight()))
	sb.WriteString(ufmt.Sprintf("- **Approved:** %t\n\n", p.Approved))

	sb.WriteString(ufmt.Sprintf("## Policy checklist\n\n"))
	sb.WriteString(check(p.TestsPass, "tests pass"))
	sb.WriteString(check(len(p.Reviews) >= MinReviewers, ufmt.Sprintf("≥%d independent reviews (have %d)", MinReviewers, len(p.Reviews))))
	minOK := true
	for _, r := range p.Reviews {
		if r.Score < MinScore {
			minOK = false
		}
	}
	sb.WriteString(check(len(p.Reviews) > 0 && minOK, ufmt.Sprintf("every review ≥%d", MinScore)))
	sb.WriteString(check(runtime.ChainHeight() > p.ChallengeUntil, "challenge window elapsed"))
	sb.WriteString("\n")

	sb.WriteString(ufmt.Sprintf("## Reviews (%d)\n\n", len(p.Reviews)))
	if len(p.Reviews) == 0 {
		sb.WriteString("_None._\n")
		return sb.String()
	}
	sb.WriteString("| Reviewer | Score | Note | Height |\n|---|---|---|---|\n")
	for _, r := range p.Reviews {
		sb.WriteString(ufmt.Sprintf("| %s | %d | %s | %d |\n", short(r.By), r.Score, r.Note, r.Height))
	}
	return sb.String()
}

func check(ok bool, label string) string {
	box := "❌"
	if ok {
		box = "✅"
	}
	return ufmt.Sprintf("- %s %s\n", box, label)
}

func parseID(s string) uint64 {
	var n uint64
	for i := 0; i < len(s); i++ {
		ch := s[i]
		assert(ch >= '0' && ch <= '9', "invalid proposal path: "+s)
		n = n*10 + uint64(ch-'0')
	}
	return n
}

func short(a address) string {
	s := a.String()
	if len(s) <= 12 {
		return s
	}
	return s[:8] + "…" + s[len(s)-4:]
}

func shortHash(s string) string {
	if len(s) <= 12 {
		return s
	}
	return s[:6] + "…" + s[len(s)-4:]
}

// Package tictactoe is a two-player tic-tac-toe realm.
//
// Join(cur, "X") / Join(cur, "O") claims a mark; Play(cur, pos) plays
// cell pos (0-8, row-major); Reset(cur) clears the board once a game
// has ended. Render shows the current board.
package tictactoe

import (
	"strconv"

	"chain"
)

const (
	empty byte = 0
	markX byte = 1
	markO byte = 2
)

var (
	board     [9]byte
	turn      byte = markX
	playerX   address
	playerO   address
	winner    byte
	moveCount int
	gameOver  bool
)

var zeroAddr address

// Join claims the X or O mark for the calling account. Each mark may
// only be claimed once per game; call Reset to start a new game.
func Join(cur realm, mark string) {
	if !cur.Previous().IsUserCall() {
		panic("EOA call only")
	}
	caller := cur.Previous().Address()
	switch mark {
	case "X":
		if playerX != zeroAddr {
			panic("X already taken")
		}
		playerX = caller
	case "O":
		if playerO != zeroAddr {
			panic("O already taken")
		}
		playerO = caller
	default:
		panic(`mark must be "X" or "O"`)
	}
	chain.Emit("Join", "player", caller.String(), "mark", mark)
}

// Play places the calling player's mark at pos (0-8, row-major).
func Play(cur realm, pos int) {
	if !cur.Previous().IsUserCall() {
		panic("EOA call only")
	}
	if gameOver {
		panic("game is over, call Reset to start a new one")
	}
	if pos < 0 || pos > 8 {
		panic("position out of range 0-8")
	}
	if board[pos] != empty {
		panic("cell already occupied")
	}

	caller := cur.Previous().Address()
	var mark byte
	if turn == markX {
		if playerX == zeroAddr {
			panic("X has not joined yet")
		}
		if caller != playerX {
			panic("not your turn")
		}
		mark = markX
	} else {
		if playerO == zeroAddr {
			panic("O has not joined yet")
		}
		if caller != playerO {
			panic("not your turn")
		}
		mark = markO
	}

	board[pos] = mark
	moveCount++
	chain.Emit("Play", "player", caller.String(), "pos", strconv.Itoa(pos))

	if w := checkWinner(); w != empty {
		winner = w
		gameOver = true
		chain.Emit("GameOver", "result", markString(w)+" wins")
	} else if moveCount == 9 {
		gameOver = true
		chain.Emit("GameOver", "result", "draw")
	} else if turn == markX {
		turn = markO
	} else {
		turn = markX
	}
}

// Reset clears the board and both player slots. Only a current player
// may reset, and only after the game has ended.
func Reset(cur realm) {
	if !cur.Previous().IsUserCall() {
		panic("EOA call only")
	}
	if !gameOver {
		panic("game still in progress")
	}
	caller := cur.Previous().Address()
	if caller != playerX && caller != playerO {
		panic("only a player of the current game may reset it")
	}

	board = [9]byte{}
	turn = markX
	winner = empty
	moveCount = 0
	gameOver = false
	playerX = zeroAddr
	playerO = zeroAddr
	chain.Emit("Reset", "by", caller.String())
}

var winLines = [8][3]int{
	{0, 1, 2}, {3, 4, 5}, {6, 7, 8},
	{0, 3, 6}, {1, 4, 7}, {2, 5, 8},
	{0, 4, 8}, {2, 4, 6},
}

func checkWinner() byte {
	for _, l := range winLines {
		a, b, c := board[l[0]], board[l[1]], board[l[2]]
		if a != empty && a == b && b == c {
			return a
		}
	}
	return empty
}

func markString(m byte) string {
	switch m {
	case markX:
		return "X"
	case markO:
		return "O"
	default:
		return "_"
	}
}

// Render draws the current board and game status as markdown.
func Render(_ string) string {
	out := "# Tic-Tac-Toe\n\n"

	out += "```\n"
	for row := 0; row < 3; row++ {
		for col := 0; col < 3; col++ {
			out += markString(board[row*3+col])
			if col < 2 {
				out += " | "
			}
		}
		out += "\n"
		if row < 2 {
			out += "---------\n"
		}
	}
	out += "```\n\n"

	out += "X: "
	if playerX == zeroAddr {
		out += "_open_"
	} else {
		out += playerX.String()
	}
	out += "\n\nO: "
	if playerO == zeroAddr {
		out += "_open_"
	} else {
		out += playerO.String()
	}
	out += "\n\n"

	switch {
	case gameOver && winner != empty:
		out += "**" + markString(winner) + " wins!** Call Reset to play again.\n"
	case gameOver:
		out += "**Draw.** Call Reset to play again.\n"
	default:
		out += "Turn: **" + markString(turn) + "**\n"
	}

	return out
}

// Package polls implements a single fixed-choice poll where each address
// may cast one vote.
package polls

import (
	"strconv"

	"gno.land/p/nt/avl/v0"
)

type option struct {
	text  string
	votes int
}

var (
	question string
	options  []*option
	voters   avl.Tree // address string -> struct{}
)

func init() {
	question = "What's your favorite gno.land feature?"
	for _, text := range []string{
		"Realms (on-chain smart contracts in Go-like Gno)",
		"GRC20 tokens",
		"Render() — realms rendering their own web pages",
		"The gnokey CLI",
	} {
		options = append(options, &option{text: text})
	}
}

// Vote casts a vote for the option at index i. Each address may vote once.
// EOA-only — MsgRun callers are rejected.
func Vote(cur realm, i int) {
	if !cur.Previous().IsUserCall() {
		panic("only a direct EOA call may vote")
	}
	if i < 0 || i >= len(options) {
		panic("invalid option index")
	}
	addr := cur.Previous().Address().String()
	if voters.Has(addr) {
		panic("this address already voted")
	}
	options[i].votes++
	voters.Set(addr, struct{}{})
}

// Render shows the poll question, options, and current vote tally.
func Render(path string) string {
	out := "# " + question + "\n\n"
	for i, o := range options {
		out += strconv.Itoa(i) + ". " + o.text + " — " + strconv.Itoa(o.votes) + " votes\n"
	}
	out += "\nCall Vote(i) with your option's index to vote.\n"
	return out
}

// Package tictactoe is a two-player tic-tac-toe realm. The first caller to
// Join becomes X, the second becomes O; players then alternate Move calls by
// cell index (0-8, left-to-right top-to-bottom) until someone wins or the
// board fills. Reset starts a fresh game once the current one has ended.
package tictactoe

import (
	"strconv"

	"chain"
)

var (
	zero address

	board   [9]string // "" empty, "X", "O"
	playerX address
	playerO address
	turn    string // "X" or "O", whose move is next
	winner  string // "", "X", "O", or "Draw"
	moves   int
)

func init() {
	turn = "X"
}

// Join seats the caller as X (if the seat is open) or O (if X is taken).
// Panics if both seats are already filled.
func Join(cur realm) string {
	caller := cur.Previous().Address()
	switch {
	case playerX == zero:
		playerX = caller
		chain.Emit("Join", "player", caller.String(), "mark", "X")
		return "joined as X"
	case playerO == zero:
		if caller == playerX {
			panic("already joined as X")
		}
		playerO = caller
		chain.Emit("Join", "player", caller.String(), "mark", "O")
		return "joined as O"
	default:
		panic("game is full")
	}
}

// Move places the caller's mark at the given cell (0-8) if it is their turn
// and the cell is empty, then checks for a win or a draw.
func Move(cur realm, pos int) {
	if winner != "" {
		panic("game already over, call Reset to start a new one")
	}
	if pos < 0 || pos > 8 {
		panic("position must be between 0 and 8")
	}
	if board[pos] != "" {
		panic("cell already occupied")
	}

	var expected address
	if turn == "X" {
		expected = playerX
	} else {
		expected = playerO
	}
	if expected == zero {
		panic("waiting for both players to join")
	}

	caller := cur.Previous().Address()
	if caller != expected {
		panic("not your turn")
	}

	board[pos] = turn
	moves++
	chain.Emit("Move", "player", caller.String(), "mark", turn, "pos", strconv.Itoa(pos))

	if checkWin(turn) {
		winner = turn
		chain.Emit("GameOver", "result", winner)
	} else if moves == 9 {
		winner = "Draw"
		chain.Emit("GameOver", "result", winner)
	} else if turn == "X" {
		turn = "O"
	} else {
		turn = "X"
	}
}

// Reset clears the board for a new game. Only callable once the current
// game has ended (someone won or the board is full).
func Reset(cur realm) {
	if winner == "" {
		panic("game still in progress")
	}
	board = [9]string{}
	playerX = zero
	playerO = zero
	turn = "X"
	winner = ""
	moves = 0
	chain.Emit("Reset")
}

var winLines = [8][3]int{
	{0, 1, 2}, {3, 4, 5}, {6, 7, 8}, // rows
	{0, 3, 6}, {1, 4, 7}, {2, 5, 8}, // columns
	{0, 4, 8}, {2, 4, 6}, // diagonals
}

func checkWin(mark string) bool {
	for _, line := range winLines {
		if board[line[0]] == mark && board[line[1]] == mark && board[line[2]] == mark {
			return true
		}
	}
	return false
}

func cell(pos int) string {
	if board[pos] == "" {
		return strconv.Itoa(pos)
	}
	return board[pos]
}

// Render draws the current board and game status as markdown.
func Render(path string) string {
	out := "# Tic-Tac-Toe\n\n"
	out += "|   |   |   |\n"
	out += "|---|---|---|\n"
	for row := 0; row < 3; row++ {
		out += "| "
		for col := 0; col < 3; col++ {
			out += cell(row*3+col) + " | "
		}
		out += "\n"
	}
	out += "\n"

	switch {
	case winner == "Draw":
		out += "**Game over: draw.**\n"
	case winner != "":
		out += "**Game over: " + winner + " wins!**\n"
	default:
		out += "Turn: **" + turn + "**\n"
	}

	out += "\nPlayer X: "
	if playerX == zero {
		out += "_(open)_"
	} else {
		out += playerX.String()
	}
	out += "\n\nPlayer O: "
	if playerO == zero {
		out += "_(open)_"
	} else {
		out += playerO.String()
	}
	out += "\n"
	return out
}
